def get_result():
  return ("Alice", 95)

tuple_result = get_result()
print(tuple_result[0], tuple_result[1])

function getResult() {
  return ["Alice", 95];
}
const [name, score] = getResult();
console.log(name, score);

class Pair<A, B> {
  A first; B second;
}
Pair<String, Integer> result = new Pair<>();
result.first = "Alice";
result.second = 95;

SELECT 'Alice' AS name, 95 AS score
UNION ALL
SELECT name, score FROM student_scores;
